namespace Exam.Core; public sealed class RelayCommand:System.Windows.Input.ICommand{readonly Action<object?> e;readonly Predicate<object?>? c;EventHandler? h;public RelayCommand(Action<object?> e,Predicate<object?>? c=null){this.e=e;this.c=c;}public bool CanExecute(object? p)=>c?.Invoke(p)??true;public void Execute(object? p)=>e(p);public event EventHandler? CanExecuteChanged{add=>h+=value;remove=>h-=value;} public void RaiseCanExecuteChanged()=>h?.Invoke(this,EventArgs.Empty);}
